sp_widget.client_script:
function ProblemToChangeCtrl($scope, spUtil) {
    var c = this;
    c.searchQuery = '';
    c.searchResults = [];
    c.searchPerformed = false;
    c.searching = false;
    c.selectedProblem = null;
    c.changeType = 'Infrastructure';
    c.startDate = null;
    c.endDate = null;
    c.isCreating = false;
    c.successMessage = null;
    c.errorMessage = null;
    c.createdChangeSysId = null;

    c.searchProblems = function() {
        if (!c.searchQuery) return;
        c.searching = true;
        c.searchPerformed = true;
        c.selectedProblem = null;
        c.errorMessage = null;
        c.server.get({action: 'searchProblems', query: c.searchQuery})
            .then(function(response) {
                c.searching = false;
                if (response.data) c.searchResults = response.data.problems || [];
            }, function() { c.searching = false; c.errorMessage = 'Search failed.'; });
    };

    c.selectProblem = function(problem) {
        c.selectedProblem = problem;
        c.errorMessage = null;
    };

    c.createChange = function() {
        if (!c.selectedProblem) return;
        c.isCreating = true;
        c.errorMessage = null;
        c.server.get({
            action: 'createChange',
            problem_sys_id: c.selectedProblem.sys_id,
            change_type: c.changeType,
            start_date: c.startDate,
            end_date: c.endDate
        }).then(function(response) {
            c.isCreating = false;
            if (response.data && response.data.success) {
                c.successMessage = response.data.message;
                c.createdChangeSysId = response.data.sys_id;
                c.data.cabRequired = response.data.cab_required;
                c.data.infrastructureType = c.changeType === 'Infrastructure';
                spUtil.publish('change.created', {changeNumber: response.data.number});
            } else {
                c.errorMessage = response.data.error || 'Failed to create change.';
            }
        }, function() { c.isCreating = false; c.errorMessage = 'An unexpected error occurred.'; });
    };

    c.reset = function() {
        c.searchQuery = '';
        c.searchResults = [];
        c.searchPerformed = false;
        c.selectedProblem = null;
        c.changeType = 'Infrastructure';
        c.startDate = null;
        c.endDate = null;
        c.successMessage = null;
        c.errorMessage = null;
        c.createdChangeSysId = null;
    };
}

sp_widget.css:
#problem-to-change { max-width: 800px; margin: 0 auto; padding: 20px; font-family: 'Segoe UI', 'Helvetica Neue', Arial, sans-serif; }
.ptc-access-denied { max-width: 500px; margin: 40px auto; }
.ptc-header { text-align: center; padding: 20px; background: linear-gradient(135deg, #e67e22 0%, #f39c12 100%); color: white; border-radius: 8px; margin-bottom: 20px; box-shadow: 0 4px 15px rgba(0,0,0,0.1); }
.ptc-header h2 { margin: 0 0 8px 0; font-size: 22px; font-weight: 300; }
.ptc-header h2 .glyphicon { margin-right: 8px; }
.ptc-header p { margin: 0; font-size: 13px; opacity: 0.9; }
.ptc-selected .alert-info { border: 1px solid #ffc107; background: #fff3cd; color: #856404; border-radius: 6px; }
.ptc-preview { font-weight: 600; color: #333; margin-top: 15px; }
.ptc-loading .spinner { width: 36px; height: 36px; border: 3px solid #f0f0f0; border-top: 3px solid #e67e22; border-radius: 50%; animation: spin 1s linear infinite; display: inline-block; }
@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }
.list-group-item { border: 1px solid #e0e0e0; margin-bottom: 4px; border-radius: 4px !important; cursor: pointer; }
.list-group-item:hover { background: #fff3cd; border-color: #ffc107; }
.list-group-item.active { background: #e67e22; border-color: #e67e22; color: white; }

sp_widget.server_script:
(function() {
    data.canCreateChange = false;
    data.problems = [];
    data.cabRequired = false;

    var cu = new ChangeUtils();
    data.canCreateChange = cu.canCreateChange();

    if (input && input.action) {
        switch (input.action) {
            case 'searchProblems':
                var problems = [];
                var query = input.query || '';
                if (query) {
                    var gr = new GlideRecord('problem');
                    gr.addEncodedQuery('numberLIKE' + query + '^ORshort_descriptionLIKE' + query);
                    gr.orderByDesc('sys_created_on');
                    gr.setLimit(20);
                    gr.query();

                    var stateLabels = {'1':'New','2':'Under Investigation','3':'Root Cause Identified','4':'Known Error','5':'Resolution Identified','6':'Resolved','7':'Closed'};
                    while (gr.next()) {
                        problems.push({
                            sys_id: gr.getUniqueValue(),
                            number: gr.getValue('number'),
                            short_description: gr.getValue('short_description'),
                            category: gr.getDisplayValue('category'),
                            subcategory: gr.getDisplayValue('subcategory'),
                            state: gr.getValue('state'),
                            state_label: stateLabels[gr.getValue('state')] || 'Unknown',
                            urgency: gr.getValue('urgency'),
                            impact: gr.getValue('impact')
                        });
                    }
                }
                data.problems = problems;
                break;

            case 'createChange':
                var result = {};
                if (input.problem_sys_id) {
                    var probGr = new GlideRecord('problem');
                    if (probGr.get(input.problem_sys_id)) {
                        var params = {type: input.change_type || 'Infrastructure'};
                        if (input.start_date) params.start_date = input.start_date;
                        if (input.end_date) params.end_date = input.end_date;
                        var changeUtil = new ChangeUtils();
                        result = changeUtil.createChangeFromProblem(probGr, params);

                        // Check if CAB is needed
                        if (result.success) {
                            var chkGr = new GlideRecord('change_request');
                            if (chkGr.get(result.sys_id)) {
                                data.cabRequired = chkGr.getValue('cab_required') === 'true';
                            }
                        }
                    } else {
                        result = {success: false, error: 'Problem not found'};
                    }
                } else {
                    result = {success: false, error: 'No problem selected'};
                }
                data.success = result.success;
                data.message = result.message;
                data.number = result.number;
                data.sys_id = result.sys_id;
                data.error = result.error;
                break;
        }
    }
})();
